parameters.jsCode:
// Get raw string
let raw = $json.data;

// Step 1: Remove wrapping quotes if present
if (raw.startsWith('"') && raw.endsWith('"')) {
  raw = raw.slice(1, -1);
}

// Step 2: Unescape characters
raw = raw
  .replace(/\\"/g, '"')   // \" → "
  .replace(/\\n/g, '\n'); // \n → actual newline

// Step 3: Clean extra blank lines (optional but nice)
raw = raw.replace(/\n{3,}/g, '\n\n').trim();

// Return as clean SRT
return [
  {
    json: {
      srt: raw
    }
  }
];

